class AddCardViewController: UIViewController {
    weak var delegate: AddCardDelegate?
    
    private let cardNumberTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Card Number"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .numberPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let expiryTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "MM/YY"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .numberPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let cvcTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "CVC"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .numberPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let saveButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Save Card", for: .normal)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 25
        button.titleLabel?.font = UIFont.boldSystemFont(ofSize: 18)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Add Card"
        view.backgroundColor = .white
        setupUI()
        setupNavigationBar()
    }
    
    private func setupNavigationBar() {
        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .cancel, 
                                                           target: self, 
                                                           action: #selector(cancelTapped))
    }
    
    private func setupUI() {
        view.addSubview(cardNumberTextField)
        view.addSubview(expiryTextField)
        view.addSubview(cvcTextField)
        view.addSubview(saveButton)
        
        NSLayoutConstraint.activate([
            cardNumberTextField.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 30),
            cardNumberTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            cardNumberTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            cardNumberTextField.heightAnchor.constraint(equalToConstant: 44),
            
            expiryTextField.topAnchor.constraint(equalTo: cardNumberTextField.bottomAnchor, constant: 20),
            expiryTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            expiryTextField.widthAnchor.constraint(equalTo: view.widthAnchor, multiplier: 0.45),
            expiryTextField.heightAnchor.constraint(equalToConstant: 44),
            
            cvcTextField.topAnchor.constraint(equalTo: cardNumberTextField.bottomAnchor, constant: 20),
            cvcTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            cvcTextField.widthAnchor.constraint(equalTo: view.widthAnchor, multiplier: 0.45),
            cvcTextField.heightAnchor.constraint(equalToConstant: 44),
            
            saveButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -30),
            saveButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            saveButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            saveButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        saveButton.addTarget(self, action: #selector(saveCard), for: .touchUpInside)
    }
    
    @objc private func cancelTapped() {
        dismiss(animated: true)
    }
    
    @objc private func saveCard() {
        guard let cardNumber = cardNumberTextField.text, !cardNumber.isEmpty,
              let expiry = expiryTextField.text, !expiry.isEmpty,
              let cvc = cvcTextField.text, !cvc.isEmpty else {
            showAlert(message: "Please fill all fields")
            return
        }
        
        let cardParams = STPCardParams()
        cardParams.number = cardNumber
        
        let expiryComponents = expiry.split(separator: "/")
        if expiryComponents.count == 2 {
            cardParams.expMonth = UInt(expiryComponents[0]) ?? 0
            cardParams.expYear = UInt(expiryComponents[1]) ?? 0
        }
        cardParams.cvc = cvc
        
        STPAPIClient.shared.createToken(withCard: cardParams) { [weak self] token, error in
            guard let self = self else { return }
            
            if let error = error {
                self.showAlert(message: "Error: \(error.localizedDescription)")
                return
            }
            
            if let token = token {
                let lastFour = String(cardNumber.suffix(4))
                self.delegate?.didAddCard("Card •••• \(lastFour)")
                self.showAlert(message: "Card added successfully!") {
                    self.dismiss(animated: true)
                }
            }
        }
    }
    
    private func showAlert(message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}

