class CheckoutViewController: UIViewController {
    var amount: Int = 0
    
    private let amountLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.boldSystemFont(ofSize: 32)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let descriptionLabel: UILabel = {
        let label = UILabel()
        label.text = "Ride Payment"
        label.font = UIFont.systemFont(ofSize: 18)
        label.textAlignment = .center
        label.textColor = .gray
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let payButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Pay Now", for: .normal)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 25
        button.titleLabel?.font = UIFont.boldSystemFont(ofSize: 18)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let activityIndicator: UIActivityIndicatorView = {
        let indicator = UIActivityIndicatorView(style: .large)
        indicator.translatesAutoresizingMaskIntoConstraints = false
        indicator.hidesWhenStopped = true
        return indicator
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Checkout"
        view.backgroundColor = .white
        setupUI()
        updateAmount()
    }
    
    private func setupUI() {
        view.addSubview(amountLabel)
        view.addSubview(descriptionLabel)
        view.addSubview(payButton)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            amountLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -50),
            amountLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            descriptionLabel.topAnchor.constraint(equalTo: amountLabel.bottomAnchor, constant: 10),
            descriptionLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            payButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -30),
            payButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            payButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            payButton.heightAnchor.constraint(equalToConstant: 50),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
        
        payButton.addTarget(self, action: #selector(processPayment), for: .touchUpInside)
    }
    
    private func updateAmount() {
        let dollars = Double(amount) / 100.0
        amountLabel.text = String(format: "$%.2f", dollars)
    }
    
    @objc private func processPayment() {
        payButton.isEnabled = false
        activityIndicator.startAnimating()
        
        let cardParams = STPCardParams()
        cardParams.number = "4242424242424242"
        cardParams.expMonth = 12
        cardParams.expYear = 25
        cardParams.cvc = "123"
        
        STPAPIClient.shared.createToken(withCard: cardParams) { [weak self] token, error in
            guard let self = self else { return }
            
            DispatchQueue.main.async {
                self.activityIndicator.stopAnimating()
                self.payButton.isEnabled = true
                
                if let error = error {
                    self.showAlert(title: "Payment Failed", message: error.localizedDescription)
                    return
                }
                
                if let token = token {
                    self.completePayment(with: token.tokenId)
                }
            }
        }
    }
    
    private func completePayment(with tokenId: String) {
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) { [weak self] in
            guard let self = self else { return }
            
            let alert = UIAlertController(title: "Payment Successful!", 
                                         message: "Your ride has been booked.", 
                                         preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
                self.navigationController?.popToRootViewController(animated: true)
            })
            self.present(alert, animated: true)
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}